INSERT INTO public.photos VALUES (24589, 'La Lonja y la puerta del â”œÃ¼ngel 1862', '"Imagen de la desaparecida Puerta del â”œÃ¼ngel, que fue erigida por el arquitecto Miguel Jeliner y Germâ”œÃ­ con motivo de la visita de Isabel II a la ciudad, en 1860. Esta puerta pretendâ”œÂ¡a recordar la antigua puerta medieval de la ciudad, que habâ”œÂ¡a sido destruida durante los Sitios (1808-1809). El grupo escultâ”œâ”‚rico del â”œÃ¼ngel Custodio, que cobija bajo sus alas una alegorâ”œÂ¡a del râ”œÂ¡o Ebro y un leâ”œâ”‚n, parece claramente un fotomontaje realizado por Jâ”œâ•‘dez a partir de una fotografâ”œÂ¡a del dibujo del proyecto." Josâ”œÂ® Antonio Hernâ”œÃ­ndez Latas. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. Colecciâ”œâ”‚n Boisset-Ibâ”œÃ­â”œâ–’ez. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza.', 1862, 1862, 1862, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65596400, -0.87601300, '0101000020E6100000FDDD3B6A4C08ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14893920231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14893920231.webp', 'https://www.flickr.com/photos/zaragozaantigua/14893920231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
