INSERT INTO public.photos VALUES (24610, 'Arco del Deâ”œÃ­n 1950', 'Arco del Deâ”œÃ­n o paso volado sobre la antigua calle de la Pabostrâ”œÂ¡a con el que se podâ”œÂ¡a acceder directamente desde la Casa del Deâ”œÃ­n de la Seo a la iglesia homâ”œâ”‚nima, en una imagen antes de ser sometido al proceso de restauraciâ”œâ”‚n que aâ”œâ–’os despuâ”œÂ®s le darâ”œÂ¡a su actual aspecto. Fuente visual: AHPZ-Archivo Coyne, Manuel Coyne', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65421200, -0.87507000, '0101000020E610000038BEF6CC9200ECBF4C530438BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14913145355.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14913145355.webp', 'https://www.flickr.com/photos/zaragozaantigua/14913145355/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
