INSERT INTO public.photos VALUES (24615, 'Arco del Deâ”œÃ­n 1975', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 23/01/1975. El restaurado Arco del Deâ”œÃ­n recuperando la funciâ”œâ”‚n para la que fue construido: gâ”œâ”‚tico garaje cubierto para vehâ”œÂ¡culos a motor de explosiâ”œâ”‚n. Como escribiâ”œâ”‚ Blasco Ijazo, "La casa da verdadero empaque a ese bello rincâ”œâ”‚n zaragozano, que mantiene toda la esencia de su tipismo en aquel contorno de la vieja ciudad." Amâ”œÂ®n. La imagen estâ”œÃ­ tomada desde la calle de Palafox, en direcciâ”œâ”‚n a la calle del Deâ”œÃ­n.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65418300, -0.87512700, '0101000020E610000048179B560A01ECBFB24CBF44BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15143864778.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15143864778.webp', 'https://www.flickr.com/photos/zaragozaantigua/15143864778/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24617, 'Arco del Deâ”œÃ­n aâ”œâ–’os 20', 'Miguel Faci Abad. 1920-25. "Zaragoza. Arco del Deâ”œÃ­n." Esta es una foto del Arco del Deâ”œÃ­n, pero que aunque no sale mâ”œÃ­s que un pedacito, es muy interesante. A nivel de suelo, desde debajo del Arco del Deâ”œÃ­n, una mirada hacia la calle del Deâ”œÃ­n, con visual a otro pasadizo voladizo, este funcional y sin pretensiones estâ”œÂ®ticas, que tambiâ”œÂ®n conectaba el complejo catedralicio con la casona de la izquierda. Ambos elementos estâ”œÃ­n hoy volados. Al fondo, las traseras de "Casa Armijo", que en tiempos tambiâ”œÂ®n formara parte del emporio eclesiâ”œÃ­stico de la Seo, como vivienda de su Arcipreste, y que ahora era propiedad de una notable familia de la ciudad, de ese apellido. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65418300, -0.87512700, '0101000020E610000048179B560A01ECBFB24CBF44BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15343174768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15343174768.webp', 'https://www.flickr.com/photos/zaragozaantigua/15343174768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24620, 'Felipe V 1701', '"Le Serment prestâ”œÂ®e par le Roy d''Espagne a Saragoce Royaume d''Aragon le 17 Septembre 1701". Ilustraciâ”œâ”‚n que recrea idealmente el juramento de los Fueros de Aragâ”œâ”‚n por parte del rey Felipe en 1701 en la La Catedral del Salvador en su Epifanâ”œÂ¡a de Zaragoza (La Seo). Esta imagen forma parte, en su parte inferior, de la estampa titulada "La benediction nuptiale donee solennellement AV / Roy et a la Reine D''Espagne a Feguieres le 5e. novembre 1701" (Boda del Rey Felipe de Borbâ”œâ”‚n con la Reina Marâ”œÂ¡a Luisa Gabriela de Saboya en la localidad catalana de Figueras. â”œÃ«l tenâ”œÂ¡a 17 aâ”œâ–’os de edad. Ella, 13). Fuente visual: gallica.bnf.fr/', 1701, 1701, 1701, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15555463059.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15555463059.webp', 'https://www.flickr.com/photos/zaragozaantigua/15555463059/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24621, 'Palmeros del Deâ”œÃ­n 1942', 'Archivo Municipal. Gerardo Sancho Ramo. 1942. Imagen de una procesiâ”œâ”‚n de palmas (plantas muy comunes en la zona) portadas por autoridades eclesiâ”œÃ­sticas varias en la calle del Deâ”œÃ­n, y acompaâ”œâ–’adas por el personal del ayuntamiento que para trabajar se pone pelucas de â”œÂ®poca. Las seâ”œâ–’oras, de negro y cubiertas, participan, pero muy en segundo plano. La procesionaria viene de la calle de la Pabostrâ”œÂ¡a, y estâ”œÃ­ a punto de llegar al antiguo arco del Deâ”œÃ­n, despuâ”œÂ®s de pasar por debajo del pasaje arquitrabado de la calle Deâ”œÃ­n que conectaba dependencias de la Seo. Esta conjunciâ”œâ”‚n entre la instituciâ”œâ”‚n municipal y una determinada confesiâ”œâ”‚n religiosa, perdura. El pasaje arquitrabado, y el edificio de la izquierda, no.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15595905729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15595905729.webp', 'https://www.flickr.com/photos/zaragozaantigua/15595905729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24623, 'Calle de Don Juan de Aragâ”œâ”‚n 1949', 'Imagen de la calle Don Juan de Aragâ”œâ”‚n, capturada desde su comienzo en la cercana plaza de Santa Marta. El edificio que recibe plena insolaciâ”œâ”‚n es el antiguo palacio de Armijo. Los edificios de la inmediata acera derecha serâ”œÃ­n piqueteados, retranqueados, y sustituidos luego por otros mâ”œÃ­s modernos, como sede de la municipal Casa de la Mujer. Fuente visual: Archivo Mora, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65394000, -0.87602000, '0101000020E61000009C8A54185B08ECBFEBC5504EB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15752862165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15752862165.webp', 'https://www.flickr.com/photos/zaragozaantigua/15752862165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24628, 'Calle del Deâ”œÃ­n 1949', 'Imagen de la calle del Deâ”œÃ­n, con el Arco del mismo nombre al fondo, soleado y en curva, antes de ser "restaurado". En primer tâ”œÂ®rmino, el arquitrabado pseudo-arco que existâ”œÂ¡a en esa calle, una antigua y prâ”œÃ­ctica costumbre de conseguir un espacio habitacional extra, sin tener que modificar el planeamiento existente, ni preocuparse por la cimentaciâ”œâ”‚n de la obra. Tiempo despuâ”œÂ®s, este "arco" y la vivienda de la que se extendâ”œÂ¡a, serâ”œÂ¡an derribados. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21810308270.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21810308270.webp', 'https://www.flickr.com/photos/zaragozaantigua/21810308270/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24629, 'Foro de Caesaraugusta aâ”œâ–’o 150', 'Plano de situaciâ”œâ”‚n del Foro Romano de Caesaraugusta, sobre una representaciâ”œâ”‚n de Zaragoza actual. Museo del Puerto Fluvial, Ayuntamiento de Zaragoza. El Foro de Caesaraugusta tenâ”œÂ¡a una superficie de casi 24.000 metros cuadrados, extendiâ”œÂ®ndose por la plaza de la Seo, el palacio arzobispal, la Casa de la Iglesia, la Seo, la plaza de San Bruno, las calles de San Valero, Cuâ”œÂ®llar y del Cisne, y gran parte de la calle de Pabostrâ”œÂ¡a. Era el centro polâ”œÂ¡tico, administrativo, religioso y econâ”œâ”‚mico de la colonia. El templo estarâ”œÂ¡a dentro de lo que hoy es la Seo, la curia en un edificio ubicado en el sureste del complejo, la basâ”œÂ¡lica en la Casa de la Iglesia y el palacio arzobispal. A ello habrâ”œÂ¡a que aâ”œâ–’adir locales comerciales, el archivo de la ciudad, la ceca donde se acuâ”œâ–’aba moneda, oficinas, un espacio destinado al culto imperial (aâ”œâ•‘n no descubierto) y conjuntos escultâ”œâ”‚ricos como una estatua ecuestre de Tiberio, en la plaza, a cielo abierto. Fuente visual: eszaragoza.blogspot.com.es/2015/10/situacion-del-foro-rom...', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65482800, -0.87568800, '0101000020E61000001EFD2FD7A205ECBFA7406667D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21897903483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21897903483.webp', 'https://www.flickr.com/photos/zaragozaantigua/21897903483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
