INSERT INTO public.photos VALUES (24650, 'Calle Sepulcro c.1975', 'Desde la calle del Sepulcro, muros y restos de edificaciones derruidas en este entorno, a izquierda y derecha, desde mediados los aâ”œâ–’os sesenta. Al fondo y tras el cubo de la Sacristâ”œÂ¡a Mayor de la Seo, los volâ”œâ•‘menes de los â”œÃ­bsides, el cimborrio y la torre campanario. A la derecha, el palacio Arzobispal. Aâ”œâ–’os mâ”œÃ­s tarde, esta zona serâ”œÃ­ muy modificada con la ampliaciâ”œâ”‚n de la plaza de San Bruno y la construcciâ”œâ”‚n de pisos de promociâ”œâ”‚n municipal.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65490600, -0.87498100, '0101000020E610000050E27327D8FFEBBF22FAB5F5D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29774366873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29774366873.webp', 'https://www.flickr.com/photos/zaragozaantigua/29774366873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24651, 'Huâ”œÂ®rfanos austrâ”œÂ¡acos 1948', 'El ejercicio de la caridad cristiana en la larga y penosa postguerra espaâ”œâ–’ola, y bajo un contexto internacional de "guerra frâ”œÂ¡a", tuvo un notable episodio en la oficial campaâ”œâ–’a que, entre 1948 y 1950, tuvo como objeto a "los fugitivos de los paâ”œÂ¡ses dominados por el comunismo bolchevique", y que tomâ”œâ”‚ cuerpo en la recepciâ”œâ”‚n de huâ”œÂ®rfanos austrâ”œÂ¡acos primero, y tambiâ”œÂ®n polacos, que fueron acogidos en calidad de "cristianos perseguidos" en la denominada "Reserva espiritual de Occidente". Sobre el origen de estos niâ”œâ–’os, las crâ”œâ”‚nicas oficiales decâ”œÂ¡an en un primer momento que eran todos huâ”œÂ®rfanos de guerra, que habâ”œÂ¡an nacido en campos de concentraciâ”œâ”‚n y que venâ”œÂ¡an desde Alemania e Italia, pero segâ”œâ•‘n la documentaciâ”œâ”‚n del International Tracing Service (Servicio Internacional de Bâ”œâ•‘squedas, archivo de la persecuciâ”œâ”‚n de minorâ”œÂ¡as y opositores polâ”œÂ¡ticos de todo tipo, la explotaciâ”œâ”‚n extrema del trabajo forzoso y el vasto desarraigo de las personas durante el gobierno del râ”œÂ®gimen nacionalsocialista en Alemania), parece ser que en realidad procedâ”œÂ¡an de los Lebensborn, o centros de experimento eugenâ”œÂ®sico para engendrar al superhombre y extender la raza aria por el orbe, bien de la uniâ”œâ”‚n obligada de mujeres seleccionadas y soldados alemanes, o bien eran arrancados de sus familias por contener los rasgos exigidos para su posterior moldeado racial. Tambiâ”œÂ®n habâ”œÂ¡a muchos con perfil ario reclutados de hijos de esclavos de la industria alemana. De esta forma, las jâ”œâ”‚venes de Acciâ”œâ”‚n Catâ”œâ”‚lica, y el Secretariado Nacional de Caridad gestionaron, junto con el Secretariado Diocesano local, el hospedaje y adopciâ”œâ”‚n temporal de estos niâ”œâ–’os centroeuropeos de planta aria que llegaron a la imperial y mariana Zaragoza. En la imagen, uno de los contingentes de peques austrâ”œÂ¡acos llegados a la ciudad. La gran mayorâ”œÂ¡a de estos niâ”œâ–’os fueron regresados luego con sus padres o familiares cercanos tras ser reclamados, pero otros (huâ”œÂ®rfanos, o de padres desaparecidos) siguieron hasta que en 1956 se hicieron cargo de', 1948, 1948, 1948, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65581700, -0.87567500, '0101000020E6100000F697DD938705ECBF9694BBCFF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30244718036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30244718036.webp', 'https://www.flickr.com/photos/zaragozaantigua/30244718036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24653, 'Arco del Deâ”œÃ­n 1943', 'Acuarela de Ambrosio Ruste, 1943. Vista del arco del Deâ”œÃ­n desde la calle de Palafox. Fuente: www.facebook.com/photo.php?fbid=10207055451304534&set...', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65446500, -0.87503500, '0101000020E61000001C5F7B664900ECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33562594714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33562594714.webp', 'https://www.flickr.com/photos/zaragozaantigua/33562594714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24655, 'Cimborrio de la Seo 1948', '"Cimborrio de la Seo, templo en que se coronaron las Reinas de Aragâ”œâ”‚n". Dibujo de los hermanos Albareda, 1948. Fuente: "Coronaciâ”œâ”‚n de las Reinas de Aragâ”œâ”‚n", La Cadiera, 1948.', 1948, 1948, 1948, 'Anos 40', 'CASCO HISTâ”œÃ´RICO', 41.65497600, -0.87540700, '0101000020E61000002810768A5503ECBF1BD5E940D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40736151224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40736151224.webp', 'https://www.flickr.com/photos/zaragozaantigua/40736151224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24659, 'Calle del Deâ”œÃ­n c.1912', 'Imagen capturada en el principio de la calle de Josâ”œÂ® Palafox y centrada en el â”œâ•‘ltimo tramo de la enrevesada calle del Deâ”œÃ­n, donde destaca el homâ”œâ”‚nimo arco medieval que conectaba los inmuebles de los nâ”œâ•‘meros 10 y 5 de esa calle, â”œÂ®ste â”œâ•‘ltimo adosado a la catedral de la Seo e inmediato a su ingreso por la Puerta de San Bartolomâ”œÂ®.', 1912, 1912, 1912, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65439600, -0.87494700, '0101000020E61000004B77D7D990FFEBBF0D51853FC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49970539642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49970539642.webp', 'https://www.flickr.com/photos/zaragozaantigua/49970539642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24660, 'Plaza de La Seo 1919', 'Aspecto de la puerta de acceso a la catedral de San Salvador o la Seo, en la plaza homâ”œâ”‚nima, durante la ceremonia de entierro de Francisco Javier Azlor de Aragâ”œâ”‚n e Idiâ”œÃ­quez (Toulouse, 1842, Madrid, 1919), VI duque de Granada de Ega. Este aristâ”œâ”‚crata fue senador del Reino desde 1877, caballero de la orden de San Juan de Malta y de la Real Maestranza de Caballerâ”œÂ¡a de Zaragoza. Sus restos fueron trasladados en tren desde la estaciâ”œâ”‚n de Atocha de Madrid.', 1919, 1919, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65509100, -0.87599000, '0101000020E6100000F2EF332E1C08ECBFB4739A05DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52024040284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52024040284.webp', 'https://www.flickr.com/photos/zaragozaantigua/52024040284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24867, 'Puente de Piedra 1991', 'Imagen capturada desde cierta altura en la Casa de la Iglesia con una vista parcial del puente de Piedra tras la importante restauraciâ”œâ”‚n del mismo inaugurada el 8 de mayo de 1991 y que le dotâ”œâ”‚ de su actual aspecto. En primer tâ”œÂ®rmino, uno de los cuatro Leones cincelados por Francisco Rallo y fundidos en bronce que flanquean los accesos al puente. Transita hacia la terminal de Zaragoza un autobâ”œâ•‘s que conecta con los municipios de Movera y Pastriz, en la margen izquierda.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65632000, -0.87594500, '0101000020E6100000F20703CFBD07ECBFF9DA334B02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50441583651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50441583651.webp', 'https://www.flickr.com/photos/zaragozaantigua/50441583651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24919, 'Caesaraugusta siglo III', '"Caesaraugusta", dibujo de Josâ”œÂ® Luis Cano que representa la puerta norte de la muralla romana junto al Ebro, de la que parte el Cardo Mâ”œÃ­ximo. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 250, 200, 299, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65639400, -0.87597000, '0101000020E61000002BDEC83CF207ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32068571131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32068571131.webp', 'https://www.flickr.com/photos/zaragozaantigua/32068571131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25063, 'Pedro Arbuâ”œÂ®s 1485', 'El martirio de san Pedro de Arbuâ”œÂ®s. Bartolomâ”œÂ® Esteban Murillo, 1664. Pedro Arbuâ”œÂ®s era Inquisidor General del Reino de Aragâ”œâ”‚n, nombrado por Torquemada en 1484. Su labor fue muy contestada. El 14 de septiembre de 1485, mientras rezaba arrodillado ante el altar mayor de La Seo, fue acuchillado por un grupo de personas. Muriâ”œâ”‚ tres dâ”œÂ¡as despuâ”œÂ®s. En 1867 fue canonizado.', 1485, 1485, 1485, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65478000, -0.87577400, '0101000020E6100000C2FC15325706ECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14994371585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14994371585.webp', 'https://www.flickr.com/photos/zaragozaantigua/14994371585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23107, 'The Cure 2000', 'Robert Smith, lâ”œÂ¡der del grupo musical britâ”œÃ­nico The Cure, actuando en la Sala Multiusos el 29 de marzo de 2000. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'UNIVERSIDAD', 41.63777500, -0.90069700, '0101000020E6100000B75ED38382D2ECBF6B9A779CA2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24536064562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24536064562.webp', 'https://www.flickr.com/photos/zaragozaantigua/24536064562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25110, 'Catedral de La Seo 1813', 'Edward Hawke Locker estuvo en Espaâ”œâ–’a como secretario de la flota britâ”œÃ­nica del Mediterrâ”œÃ­neo en el otoâ”œâ–’o de 1813, y en plena guerra pudo visitar, acompaâ”œâ–’ando al ejâ”œÂ®rcito del Mariscal de Campo Arthur Wellesley, algunas provincias espaâ”œâ–’olas del interior, como Zaragoza, en la que estuvo poco despuâ”œÂ®s de la salida de las tropas francesas, recogiendo estampas grâ”œÃ­ficas, como la que ilustra esta entrada. En ella, aparece la fachada de la catedral de San Salvador, el Arco del Arzobispo, y la fachada del Palacio Arzobispal, que entonces aâ”œâ•‘n presentaba esa llamativa esquina de acceso desde la plaza de la Seo, cuando el edificio de la antigua Diputaciâ”œâ”‚n del Reino no estaba alineado con el Palacio Arzobispal. "Vistas de Espaâ”œâ–’a" fue el resultado de este viaje de Locker, publicado por entregas casi inmediatamente. En 1824 se editâ”œâ”‚ como libro, y de allâ”œÂ¡ procede esta imagen. Fuente visual: Edward Hawke Locker, 1824, Cathedral del Seu: Zaragoza. Fondo Documental Histâ”œâ”‚rico de las Cortes de Aragâ”œâ”‚n.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65501400, -0.87602500, '0101000020E61000000E4FAF946508ECBF0936AE7FD7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877516232.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877516232.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877516232/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
