INSERT INTO public.photos VALUES (25141, '&quot;Cathedral del Seu&quot; 1813', 'Edward Hawke Locker estuvo en Espaâ”œâ–’a como secretario de la flota britâ”œÃ­nica del Mediterrâ”œÃ­neo en el otoâ”œâ–’o de 1813, y en plena guerra contra la Francia napoleâ”œâ”‚nica pudo visitar, acompaâ”œâ–’ando al ejâ”œÂ®rcito del Mariscal de Campo Arthur Wellesley, algunas provincias espaâ”œâ–’olas del interior, como Zaragoza, en la que estuvo poco despuâ”œÂ®s de la salida de las tropas francesas, recogiendo estampas grâ”œÃ­ficas, como la que ilustra esta entrada. En ella, aparece la fachada de la catedral de San Salvador, el Arco del Arzobispo, y la fachada del Palacio Arzobispal, que entonces aâ”œâ•‘n presentaba una llamativa esquina de acceso desde la plaza de la Seo, cuando el edificio de la antigua Diputaciâ”œâ”‚n del Reino no estaba alineado con el Palacio Arzobispal. "Views in Spain" ("Vistas de Espaâ”œâ–’a") fue el resultado editorial de este viaje de Locker, publicado por entregas casi inmediatamente en Inglaterra. En 1824 se editâ”œâ”‚ ya como libro, en Londres, por John Murray, y de allâ”œÂ¡ procede esta imagen a color, que es una litografâ”œÂ¡a realizada por James Duffield Harding. Fuente visual: Edward Hawke Locker, "Cathedral del Seu. Zaragoza", amablemente aportada por Josâ”œÂ® Luis Cintora, de su Archivo particular.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23055255321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23055255321.webp', 'https://www.flickr.com/photos/zaragozaantigua/23055255321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25147, 'La Seo 1710', 'Dibujo de Jesâ”œâ•‘s â”œÃ¼ngel Pâ”œÂ®rez Casas recreando el aspecto figurado que tendrâ”œÂ¡a la Seo antes de que le fuese adosada la portada barroca neoclâ”œÃ­sica sobre la anterior, gâ”œâ”‚tico-mudâ”œÂ®jar.', 1710, 1710, 1710, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65518900, -0.87592400, '0101000020E61000001502B9C49107ECBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27940513550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27940513550.webp', 'https://www.flickr.com/photos/zaragozaantigua/27940513550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25418, 'Puente de Piedra c.1955', 'Imagen de un dâ”œÂ¡a de niebla en el puente de Piedra donde se encuentra con la ribera derecha, y entronca con el paseo de la Ribera (actual Echegaray y Caballero) y con la calle Don Jaime I (justo donde un seâ”œâ–’or cruza por un imaginario paso de peatones, sâ”œâ”‚lo existente en la actualidad). La permanencia de los raâ”œÂ¡les del tranvâ”œÂ¡a paralelos al râ”œÂ¡o, un recuerdo de la lâ”œÂ¡nea de "Circunvalaciâ”œâ”‚n", clausurada en 1943, aâ”œâ•‘n aguantarâ”œÂ¡a algâ”œâ•‘n quinquenio mâ”œÃ­s. La imagen, en altura, se habrâ”œÂ¡a capturado desde el edificio arzobispal anexo al Palacio de la misma titularidad. Fuente visual: Archivo Coyne, en AHPZ.', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65639400, -0.87574200, '0101000020E6100000EA7937161406ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15795092596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15795092596.webp', 'https://www.flickr.com/photos/zaragozaantigua/15795092596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25425, 'Club Nâ”œÃ­utico 1966', 'Vista del puente de Piedra de Zaragoza, con el Club Nâ”œÃ­utico en el paseo de Echegaray y Caballero. Fuente: "Espaâ”œâ–’a, quâ”œÂ® hermosa eres", 1966.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65654200, -0.87601100, '0101000020E6100000CFF57D384808ECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19929585034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19929585034.webp', 'https://www.flickr.com/photos/zaragozaantigua/19929585034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25440, 'Râ”œÂ¡o Ebro 1955', 'Excepcional e insâ”œâ”‚lita imagen del râ”œÂ¡o Ebro capturada desde la orilla derecha, inmediata al medieval puente de Piedra, durante uno de esos prolongados y caniculares perâ”œÂ¡odos de tiempo en que el râ”œÂ¡o parece bien poca cosa, aunque no lo sea. El bajo nivel de las aguas permite una interesante visual de las antiguas estacas de madera colocadas para crear un pequeâ”œâ–’o azud que remansaba agua para los molinos que la energâ”œÂ¡a del râ”œÂ¡o impulsaba. Es tiempo, tambiâ”œÂ®n de pesca, y de moderados baâ”œâ–’os de sol. La navegaciâ”œâ”‚n parece poco probable. Esta captura fue realizada por el fotâ”œâ”‚grafo francâ”œÂ®s Jean Paul Margnac en el verano de 1955, durante su paso por la penâ”œÂ¡nsula Ibâ”œÂ®rica, desde Parâ”œÂ¡s, y con destino hacia tierras mâ”œÃ­s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/26452547350/in/al...', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65635400, -0.87566400, '0101000020E6100000FC1A49827005ECBFA54C6A6803D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26695916553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26695916553.webp', 'https://www.flickr.com/photos/zaragozaantigua/26695916553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
