INSERT INTO public.photos VALUES (25501, 'Puerta del â”œÃ¼ngel 1493', '"Primera Puerta del â”œÃ¼ngel", Antonio Callaved, 2011. Representaciâ”œâ”‚n idealizada de la "Primera Puerta del â”œÃ¼ngel", que cerraba Zaragoza en el perâ”œÂ¡metro de la muralla, zona norte. Fue reconstruida en 1523. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1493, 1493, 1493, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65617300, -0.87588000, '0101000020E61000002C0E677E3507ECBF55C2137AFDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15278414822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15278414822.webp', 'https://www.flickr.com/photos/zaragozaantigua/15278414822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
