INSERT INTO public.photos VALUES (25506, 'Llegada de Santiago, 1490', 'Viaje de Santiago desde Jerusalâ”œÂ®n a Zaragoza (1490). Sarga o tapiz conservada en la sacristâ”œÂ¡a del Pilar de Zaragoza que representa al apâ”œâ”‚stol llegando a la ciudad en el aâ”œâ–’o 40, aunque la representaciâ”œâ”‚n de la puerta del Puente en la muralla corresponde a la â”œÂ®poca en que fue realizada la imagen. Fuente: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1490, 1490, 1490, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16270192280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16270192280.webp', 'https://www.flickr.com/photos/zaragozaantigua/16270192280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25507, 'Basilio Boggiero 1809', 'Dibujo de Manuel Lahoz, 1959. Del libro "Los escolapios y los Sitios de Zaragoza", 1959. Recreaciâ”œâ”‚n de la muerte del sacerdote consejero del General Palafox, el sacerdote Basilio Boggiero, durante el sitio de Zaragoza de 1809. Se reproduce la puerta del â”œÃ¼ngel al fondo y dos de los leones del puente de Piedra por los suelos. Fuente: www.asociacionlossitios.com/padreboggiero.htm', 1809, 1809, 1809, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65639400, -0.87574200, '0101000020E6100000EA7937161406ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19083607386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19083607386.webp', 'https://www.flickr.com/photos/zaragozaantigua/19083607386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
