INSERT INTO public.photos VALUES (20874, 'Puerta del Puente c.1150', 'Letra capitular que aparece en el tomo V del cartulario o Privilegios de la ciudad de Zaragoza (1549-1552). La iconografâ”œÂ¡a utilizada copia documentos mâ”œÃ­s antiguos. En la miniatura se ve la puerta del Puente (luego del â”œÃ¼ngel), la muralla y el puente de madera altomedieval. En 1188, el puente dejâ”œâ”‚ de ser de madera. Hasta el siglo XV no se construyâ”œâ”‚ el que perdura hoy, llamado de las piedras o de Piedra. Fuente: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1150, 1150, 1150, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65662200, -0.87575300, '0101000020E6100000E4F6CB272B06ECBFC4EA8F300CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15834829934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15834829934.webp', 'https://www.flickr.com/photos/zaragozaantigua/15834829934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21007, 'Puente de Piedra 1860', '"Puente sobre el Ebro". Una de las fotos mâ”œÃ­s antiguas del Pilar de Zaragoza, sin la gran câ”œâ•‘pula central. El puente de Piedra todavâ”œÂ¡a presenta las pilastras pares acondicionadas como antiguas viviendas. Fuente visual: Charles Clifford, en Biblioteca Nacional de Espaâ”œâ–’a.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14917766140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14917766140.webp', 'https://www.flickr.com/photos/zaragozaantigua/14917766140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21025, 'El Pilar 1868', 'Recuerda Benito Pâ”œÂ®rez Galdâ”œâ”‚s en sus "Memorias de un desmemoriado", que en 1868, con motivo de la Exposiciâ”œâ”‚n Aragonesa celebrada ese aâ”œâ–’o en Zaragoza, se cursâ”œâ”‚ invitaciâ”œâ”‚n oficial a los generales Serrano y Topete, como protagonistas de la "Gloriosa" revoluciâ”œâ”‚n que acababa de derribar del trono a los Borbones. Galdâ”œâ”‚s, en su calidad de periodista, formâ”œâ”‚ parte de la comitiva que llegâ”œâ”‚ desde Madrid en tren a Campo Sepulcro. La recepciâ”œâ”‚n popular fue memorable, con cabalgatas, discursos, aclamaciones, mâ”œâ•‘sicas, algarabâ”œÂ¡as varias, funciâ”œâ”‚n teatral en el Principal, banquete... Al dâ”œÂ¡a siguiente, Galdâ”œâ”‚s paseâ”œâ”‚ por la ciudad "sin guâ”œÂ¡a", en un periplo que le llevâ”œâ”‚ por el Coso, el Mercado, el Pilar, y la Seo. Mâ”œÃ­s tarde, continuâ”œâ”‚ por la Torre Nueva, la Escuela Pâ”œÂ¡a, y San Pablo. Al dâ”œÂ¡a siguiente, por la puerta del Carmen, la Trinidad, la Aljaferâ”œÂ¡a, subiâ”œâ”‚ hasta el Torrero, y luego bajâ”œâ”‚ hasta las ruinas de San Agustâ”œÂ¡n. La imagen reproduce el dibujo que Galdâ”œâ”‚s realizâ”œâ”‚ "a pluma" desde la margen izquierda del Ebro, donde el antiguo convento de San Lâ”œÃ­zaro, capturando una reconocible y familiar vista parcial del puente de Piedra, con el templo del Pilar al fondo. Fuente visual: Revista "La Esfera" (Madrid).', 1868, 1868, 1868, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22320420423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22320420423.webp', 'https://www.flickr.com/photos/zaragozaantigua/22320420423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
