INSERT INTO public.photos VALUES (21083, '&quot;Puente Pietra&quot;, c.1878', 'Imagen titulada "The city of Saragossa. Bridge Puente Pietra", que resulta beber de las mismas fuentes que la tercera de las tres vistas capturadas por Jean Laurent y Câ”œÂ¡a. hacia 1873, y que forman el extraordinario trâ”œÂ¡ptico "Vista general desde Altabas". Esta toma se centra en el puente de Piedra, y la fachada de la ciudad al Ebro desde las Casas Consistoriales, hasta el barrio de San Pablo. La gran câ”œâ•‘pula central del Pilar, y las câ”œâ•‘pulas del Coro, terminadas.', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65735600, -0.87530500, '0101000020E610000018CFA0A17F02ECBF29EACC3D24D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26584473426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26584473426.webp', 'https://www.flickr.com/photos/zaragozaantigua/26584473426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
